using HTX586CONTRACT.Domain.Signatures; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace HTX586CONTRACT.Infrastructure.Persistence.Configurations;
public sealed class ContractSignatureConfiguration:IEntityTypeConfiguration<ContractSignature>{public void Configure(EntityTypeBuilder<ContractSignature>b){b.ToTable("ContractSignatures",t=>{t.HasCheckConstraint("CK_ContractSignatures_Latitude","[Latitude] IS NULL OR ([Latitude] >= -90 AND [Latitude] <= 90)");t.HasCheckConstraint("CK_ContractSignatures_Longitude","[Longitude] IS NULL OR ([Longitude] >= -180 AND [Longitude] <= 180)");});b.HasKey(x=>x.Id);b.Property(x=>x.SignerName).HasMaxLength(200).IsRequired();b.Property(x=>x.SignerPhone).HasMaxLength(20);b.Property(x=>x.SignatureFileUrl).HasMaxLength(500).IsRequired();b.Property(x=>x.SignatureHash).HasMaxLength(128).IsRequired();b.Property(x=>x.ContractHashAtSigning).HasMaxLength(128).IsRequired();b.Property(x=>x.Latitude).HasPrecision(10,7);b.Property(x=>x.Longitude).HasPrecision(10,7);b.Property(x=>x.LocationAddress).HasMaxLength(500);b.Property(x=>x.IpAddress).HasMaxLength(64);b.Property(x=>x.DeviceId).HasMaxLength(200);b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.Contract).WithMany(x=>x.Signatures).HasForeignKey(x=>x.ContractId).OnDelete(DeleteBehavior.Restrict);b.HasIndex(x=>new{x.ContractId,x.Party}).IsUnique().HasFilter("[IsDeleted] = 0").HasDatabaseName("UX_ContractSignatures_Contract_Party");b.HasIndex(x=>x.ServerSignedAt).IsDescending().HasDatabaseName("IX_ContractSignatures_ServerSignedAt");b.HasQueryFilter(x=>!x.IsDeleted);}}
